package com.speedster.payload

import android.content.Context
import android.view.accessibility.AccessibilityEvent
import android.view.accessibility.AccessibilityNodeInfo
import androidx.compose.runtime.*
import com.speedster.DynamicEntry
import java.io.File

class PayloadEntry : DynamicEntry {
    override @Composable fun Render(context: Context, resDir: File) {
        LaunchedEffect(Unit) {
            DynamicEntry.log("🔍 Node Sniffer Active. Change windows to scan.")

            DynamicEntry.accessibilityInterceptor = { event ->
                if (event.eventType == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED || 
                    event.eventType == AccessibilityEvent.TYPE_WINDOW_CONTENT_CHANGED) {

                    val root = DynamicEntry.activeAccessibilityService?.rootInActiveWindow
                    root?.let {
                        val nodes = mutableListOf<String>()
                        dumpNode(it, nodes, 0)
                        if (nodes.isNotEmpty()) {
                            DynamicEntry.systemLogs.clear()
                            DynamicEntry.systemLogs.addAll(nodes)
                        }
                    }
                }
            }
        }
    }

    private fun dumpNode(node: AccessibilityNodeInfo?, results: MutableList<String>, depth: Int) {
        if (node == null) return
        if (results.size > 200) return // Safety cap

        val id = node.viewIdResourceName ?: "no-id"
        val text = node.text?.toString() ?: ""
        val desc = node.contentDescription?.toString() ?: ""

        if (id != "no-id" || text.isNotBlank() || desc.isNotBlank()) {
            val indent = "  ".repeat(depth)
            results.add("$indent[$id] T:$text D:$desc")
        }

        for (i in 0 until node.childCount) {
            dumpNode(node.getChild(i), results, depth + 1)
        }
    }
}

